function autoFormatTime(D){let U=D['value']['replace'](/\D/g,'');switch(U['length']>0x4&&(U=U['slice'](0x0,0x4)),U['length']){case 0x0:case 0x1:case 0x2:D['value']=U;break;case 0x3:if(parseInt(U['slice'](0x0,0x2),0xa)<=0x17)D['value']=U['slice'](0x0,0x2)+':'+U['slice'](0x2);else{let q=U['slice'](0x0,0x1)['padStart'](0x2,'0'),b=U['slice'](0x1);D['value']=q+':'+b;}break;case 0x4:let y=U['slice'](0x0,0x2),k=U['slice'](0x2);D['value']=y+':'+k;}}function transformTimeValue(D){let U=D['trim']();if(/^\d{2}$/['test'](U))return U[0x0]['padStart'](0x2,'0')+':'+U[0x1]['padStart'](0x2,'0');if(/^\d{3,4}$/['test'](U))return 0x3===U['length']?parseInt(U['slice'](0x0,0x2),0xa)<=0x17?U['slice'](0x0,0x2)+':'+U['slice'](0x2):U['slice'](0x0,0x1)['padStart'](0x2,'0')+':'+U['slice'](0x1):U['slice'](0x0,0x2)+':'+U['slice'](0x2);if(U['includes'](':')){let [y,k]=U['split'](':');return k||(k='00'),y=y['padStart'](0x2,'0'),k=k['padStart'](0x2,'0'),y+':'+k;}return U;}